using System;

class Program
{
    // Basit fonksiyon
    static int Square(int x)
    {
        return x * x;
    }

    // Birden fazla parametre
    static int Add(int a, int b)
    {
        return a + b;
    }

    // Opsiyonel parametre
    static string Greet(string name, string greeting = "Merhaba")
    {
        return greeting + ", " + name + "!";
    }

    // Fonksiyon overload
    static double Multiply(double a, double b)
    {
        return a * b;
    }

    static int Multiply(int a, int b)
    {
        return a * b;
    }

    static void Main()
    {
        Console.WriteLine("Kare: " + Square(5));
        Console.WriteLine("Toplam: " + Add(3, 7));
        Console.WriteLine(Greet("Ayse"));
        Console.WriteLine(Greet("Mehmet", "Selam"));
        Console.WriteLine("Tam carpim: " + Multiply(4, 5));
        Console.WriteLine("Ondalik carpim: " + Multiply(2.5, 3.0));
    }
}
